import { Field, FieldDescription, FieldLabel } from "@/components/ui/field";
import { Input } from "@/components/ui/input";

export function InputField({
  label,
  placeholder,
  description,
  onChange,
}: {
  label: string;
  placeholder: string;
  description: string;
  onChange: (e: any) => void;
}) {
  return (
    <Field>
      <FieldLabel htmlFor="input-field-slug">{label}</FieldLabel>
      <Input
        id="input-field-slug"
        type="text"
        placeholder={placeholder}
        onChange={onChange}
      />
      <FieldDescription>{description}</FieldDescription>
    </Field>
  );
}
